t.script:
document.addEventListener('DOMContentLoaded', function() {
    // Get all editable fields
    var fields = document.querySelectorAll('.editable-field');

    fields.forEach(function(field) {
        var oldValue = field.getAttribute('data-old-value');
        // Find the .old-value-display sibling
        var wrapper = field.closest('.field-group') || field.parentElement;
        var display = wrapper.querySelector('.old-value-display');

        if (!display) return;

        // Build the old value content
        var displayText = oldValue ? oldValue : '(Chưa có dữ liệu)';
        display.innerHTML =
            '📌 Giá trị hiện tại:' +
            '' + displayText + '' +
            '✕';

        // Show on focus/click
        field.addEventListener('focus', function() {
            display.classList.add('show');
        });

        field.addEventListener('click', function() {
            display.classList.add('show');
        });

        // Close button
        var closeBtn = display.querySelector('.old-value-close');
        if (closeBtn) {
            closeBtn.addEventListener('click', function(e) {
                e.preventDefault();
                e.stopPropagation();
                display.classList.remove('show');
            });
        }
    });

    // Tab activation from URL hash
    var hash = window.location.hash;
    if (hash === '#onboard') {
        var tabEl = document.querySelector('#onboard-tab');
        if (tabEl) {
            var tabTrigger = new bootstrap.Tab(tabEl);
            tabTrigger.show();
        }
    }

    // ====== LOC TINH THANH THEO QUOC GIA ======
    // Find country and state selects by name
    var countrySelect = document.querySelector('select[name="private_country_id"]');
    var stateSelect = document.querySelector('select[name="private_state_id"]');

    if (countrySelect) {
        if (stateSelect) {
            var stateOptions = Array.from(stateSelect.querySelectorAll('option'));

            function filterStates() {
                var selectedCountryId = countrySelect.value;
                var hasValidOption = false;

                stateOptions.forEach(function(opt) {
                    // Default placeholder option always shown
                    if (!opt.value) {
                        opt.style.display = '';
                        return;
                    }

                    var optCountryId = opt.getAttribute('data-country-id');
                    if (!selectedCountryId) {
                        opt.style.display = '';
                        hasValidOption = true;
                    } else if (optCountryId === selectedCountryId) {
                        opt.style.display = '';
                        hasValidOption = true;
                    } else {
                        opt.style.display = 'none';
                    }
                });

                // If current selected state is now hidden (doesn't match country), reset state to empty
                var selectedStateOpt = stateSelect.options[stateSelect.selectedIndex];
                if (selectedStateOpt) {
                    if (selectedStateOpt.style.display === 'none') {
                        stateSelect.value = '';
                        // Trigger change to remove any '.old-value-display' visual issues
                        stateSelect.dispatchEvent(new Event('change'));
                    }
                }
            }

            // Initial filter on page load
            filterStates();

            // Filter on country change
            countrySelect.addEventListener('change', filterStates);
        }
    }
});
